#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    char name[101];
    int power;
    char city[101];
} Hero;

int cmp(const void *a, const void *b) {
    const Hero *h1 = (const Hero *)a;
    const Hero *h2 = (const Hero *)b;
    if (h1->power != h2->power) return h2->power - h1->power; // descending power
    return strcmp(h1->name, h2->name); // ascending name
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Hero *arr = (Hero *)malloc(N * sizeof(Hero));
        for (int i = 0; i < N; ++i) {
            scanf("%s %d %s", arr[i].name, &arr[i].power, arr[i].city);
        }
        qsort(arr, N, sizeof(Hero), cmp);
        for (int i = 0; i < N; ++i) {
            printf("%s (%d) - %s\n", arr[i].name, arr[i].power, arr[i].city);
        }
        free(arr);
    }
    return 0;
}

