#include <bits/stdc++.h>
using namespace std;

struct Hero {
    string name;
    int power;
    string city;
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<Hero> v(N);
        for (int i = 0; i < N; ++i) {
            cin >> v[i].name >> v[i].power >> v[i].city;
        }
        sort(v.begin(), v.end(), [](const Hero &a, const Hero &b) {
            if (a.power != b.power) return a.power > b.power; // descending power
            return a.name < b.name; // ascending name
        });
        for (const auto &h : v) {
            cout << h.name << " (" << h.power << ") - " << h.city << '\n';
        }
    }
    return 0;
}

