import java.io.*;
import java.util.*;

public class Main {
    static class Hero {
        String name;
        int power;
        String city;
        Hero(String n, int p, String c) { name = n; power = p; city = c; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Hero> list = new ArrayList<>(N);
            for (int i = 0; i < N; ++i) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                String name = st.nextToken();
                int power = Integer.parseInt(st.nextToken());
                String city = st.nextToken();
                list.add(new Hero(name, power, city));
            }
            list.sort((a, b) -> {
                if (a.power != b.power) return Integer.compare(b.power, a.power); // descending
                return a.name.compareTo(b.name); // ascending
            });
            for (Hero h : list) {
                out.append(h.name).append(" (").append(h.power).append(") - ").append(h.city).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

