const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\n/);
let idx = 0;
if (input.length === 1 && input[0] === '') process.exit(0);
const T = parseInt(input[idx++], 10);
let output = [];
for (let t = 0; t < T; ++t) {
  const N = parseInt(input[idx++], 10);
  let heroes = [];
  for (let i = 0; i < N; ++i) {
    const [name, powerStr, city] = input[idx++].trim().split(/\s+/);
    heroes.push({name, power: parseInt(powerStr, 10), city});
  }
  heroes.sort((a, b) => {
    if (a.power !== b.power) return b.power - a.power; // descending power
    return a.name < b.name ? -1 : a.name > b.name ? 1 : 0; // ascending name
  });
  for (const h of heroes) {
    output.push(`${h.name} (${h.power}) - ${h.city}`);
  }
}
console.log(output.join('\n'));
